using System.Security.Cryptography;
namespace GiblexVault.Security.ZK.Primitives { public static class Hkdf { public static byte[] Sha256(byte[] ikm, byte[] salt, byte[] info, int len = 32) { using var hmac = new HMACSHA256(salt); var prk = hmac.ComputeHash(ikm); var t = Array.Empty<byte>(); var okm = new System.Collections.Generic.List<byte>(len); byte c = 1; while (okm.Count < len) { hmac.Key = prk; var input = new byte[t.Length + info.Length + 1]; Buffer.BlockCopy(t, 0, input, 0, t.Length); Buffer.BlockCopy(info, 0, input, t.Length, info.Length); input[^1] = c++; t = hmac.ComputeHash(input); okm.AddRange(t); } return okm.GetRange(0, len).ToArray(); } } }